var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지가 보스였을 때는 사업하기 참 좋은 시절이었어.","JPN":"父がボスだった頃はちょうど事業がうまくいっていた時期だった。","ENG":"When my father was the Don, it was easy to do business.","TWN":"父親當老闆的時候，正是事業上升期。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"전쟁으로 생긴 건설 호황, 치안 공백, 용병업이 흥하면서 활발해진 무기 밀거래......","JPN":"戦争後の建設好況、治安の悪化、傭兵業が盛んで活発になった武器密売……","ENG":"The war left us with a construction boom, weak law enforcement, and mercenaries who needed black market weapons...","TWN":"戰爭產生的建設繁榮、治安不佳、傭兵業興盛，還有盛行的武器走私……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"전부 아버지의 든든한 비즈니스 파트너였지.","JPN":"ある意味、すべてが父のビジネスパートナーだった。","ENG":"Everyone was a solid business partner for my father back then.","TWN":"全部都是父親可靠的商業夥伴。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"문제는 아무리 꼼꼼하게 바른 벽지도, 시간이 지나면 언젠가 닳아 떨어진다는 거야.","JPN":"問題はいくら念入りに張った壁紙でも、時間が経つにつれ劣化して剝がれ落ちるってこと。","ENG":"The trouble is, even the sturdiest castle wears down and crumbles with time.","TWN":"但問題是，無論多麼認真仔細貼上的壁紙，隨著時間的推移，總有一天也是會磨損掉落的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아르세니코 패밀리는...... 다른 것들보다 조금 더 빨랐어.","JPN":"アルセニコファミリーには……他の連中よりその時が早く来てしまった。","ENG":"As for the Arsenicos... that time came sooner than most.","TWN":"阿塞妮克家族……相對來說速度更快一些。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"범인은 아직 못 찾았답니까?","JPN":"犯人はまだ見つかってないんですか？","ENG":"They haven't found the culprit yet?","TWN":"犯人還沒有抓到嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"경찰들도 뚜렷한 단서가 없다고 하더라.","JPN":"警察も明確な手がかりがないと言っていた。","ENG":"Even the police said they didn't have any clear leads.","TWN":"員警也說沒有明確的線索。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"냉정하게 생각해, 리타. 사고일 가능성도 고민해 봐야지.","JPN":"冷静に考えろ、リタ。事故の可能性も考えないと。","ENG":"You've got to be clear-eyed about this sort of stuff, Rita. There's always the possibility that it was an accident.","TWN":"麗塔，你冷靜想一想，也可能就只是意外呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"숙부님이야말로 냉정해지시죠.","JPN":"叔父さんこそ、冷静になってください。","ENG":"You're the one who should clear your eyes, uncle.","TWN":"叔父您才應該冷靜吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"확률이 0인 가능성을 고민하는 건 시간 낭비일 뿐입니다.","JPN":"確率が0の可能性を悩むのは時間の無駄です。","ENG":"It's a waste of time considering the possibility of the improbable.","TWN":"思考一件可能性為零的事情不過是浪費時間而已。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"차 밑에서 뭔가가 폭발했습니다. 숙부님.","JPN":"車の下で何かが爆発したのです。","ENG":"Something blew up under the car. Uncle.","TWN":"車底好像有什麼東西爆炸了，叔父。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"다른 곳도 아니고, 아르세니코 패밀리의 보스가 앉아 있던 좌석 바로 밑에서.","JPN":"他の場所ではなく、アルセニコファミリーのボスが座っていた座席のすぐ下で。","ENG":"Right under the Arsenicos' boss, no less.","TWN":"不是其他地方，就在阿塞妮克家族老大的座椅下面。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저한테는 가스관이 폭발했다는 추측보다 누군가 차 밑에 폭발물을 심어 뒀다는 쪽이 더 설득력 있게 느껴지는군요.","JPN":"私にはガス管が爆発したという推測よりも、誰かが車の下に爆発物を仕組んだという話が一番説得力があると思います。","ENG":"To me, the possibility of someone planting explosives under the car seems a lot more plausible than this gas pipe explosion theory.","TWN":"在我看來，比起排氣管道爆炸的推測，更有可能是有人在車底安裝了爆炸物。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"네가 예민하게 굴 만한 일이라는 건 나도 알아. 그래도......","JPN":"君が敏感になっても仕方ないことは私も理解している。それでも……","ENG":"I completely understand why you'd be so touchy about this. Still...","TWN":"我知道你對這件事非常敏感。但是……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 병상만 봐도 그렇습니다.","JPN":"この病室もそうです。","ENG":"Look around you.","TWN":"看看這個病床。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지 몸에 생채기만 나도 호들갑 떨던 자들이 얼굴 한 번 안 비추지 않습니까.","JPN":"父の体にできたちょっとした傷でも大げさに騒いでいた者たちが、一度も顔を出さないなんて。","ENG":"All those goons who'd flip out over a scratch on father's body... where are they now?","TWN":"那些以前只要父親受了一點點傷就大呼小叫的人，現在連影子都找不到了？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"크흠......","JPN":"コホン……","ENG":"Ahem...","TWN":"咳咳……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};